def grayCode(self, n: int) -> List[int]:
    sequence = [0] * (1 << n)
    for i in range(1 << n):
        for j in range(1 << (n - 1)):
            temp = (i | j) ^ (i & j)
            if temp != i:
                sequence.append(temp)
    return sequence

